// generar_258_vet_medicamento_estado_derivado.js
// CHIQUI Entre Señales — Fix: /vet mostraba medicamento "Activo" con
// fecha de fin ya pasada
//
// Mismo bug de raíz que arreglamos en Prevención (246/247) y el
// dashboard, pero en la vista del veterinario: /vet clasificaba y
// etiquetaba los medicamentos mirando solo el campo estado de la base,
// que no se actualiza solo cuando pasa la fecha_fin.
//
// Fix: nueva función medicamentoEstaActivo(med) — activo solo si
// estado='activo' Y (sin fecha_fin O fecha_fin >= hoy, zona horaria
// America/Santiago). Se aplica en los DOS lugares que decidían:
//   1) La separación "activos primero / Finalizados (N) colapsados".
//   2) El badge Activo/Finalizado de cada tarjeta.
//
// Con esto, un tratamiento cuya fecha de término ya pasó aparece para
// el veterinario en la sección de Finalizados con su badge gris,
// igual que lo ve el tutor en Prevención.
//
// Solo reescribe app/vet/page.tsx. No hay SQL.
//
// Uso:
//   node generar_258_vet_medicamento_estado_derivado.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/vet/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
